Code
def is_hermitian(A):
    return np.allclose(A, A.conj().T)

def is_unitary(U):
    return np.allclose(U.conj().T @ U, np.eye(U.shape[0]))

def is_normal(A):
    return np.allclose(A.conj().T @ A, A @ A.conj().T)

